// Create a yellow cross marker on Mars
var marsMarker = MarkerMgr.markerObject("Mars", true, "cross", "#ffff00", 8);
core.debug("Mars marker ID: " + marsMarker);

// Create a red circled-cross marker on Betelgeuse
var betelgeuseMarker = MarkerMgr.markerObject("Betelgeuse", true, "circled-cross", "#ff4444", 10);

// Create a temporary target marker that auto-deletes after 5 seconds
var tempMarker = MarkerMgr.markerObject("Jupiter", true, "target", "#ffaa00", 12, false, 5000);

// Hide the marker later
MarkerMgr.setMarkerShow(marsMarker, false);

// Mark the position of the Orion Nebula (M42) with a circle
var m42Marker = MarkerMgr.markerEquatorial("5h35m17s", "-5°23′28″", true, true, "circle", "#ff8888", 10);

// Mark the position of the North Celestial Pole with a target
var ncpMarker = MarkerMgr.markerEquatorial("0h", "+90°", true, true, "target", "#ffffff", 12);

// Mark the galactic center with a gear shape
var galacticCenter = MarkerMgr.markerEquatorial("17h45m40s", "-29°00′28″", true, true, "gear", "#ffcc66", 14);

// Create a precise marker without aberration
var preciseMarker = MarkerMgr.markerEquatorial("6h45m09s", "-16°43′06″", true, true, "cross", "#66ff66", 6, false, 0, false);

// Mark the four cardinal points on the horizon
var northMarker = MarkerMgr.markerHorizon("0°", "0°", true, "target", "#ff0000", 10);
var eastMarker = MarkerMgr.markerHorizon("90°", "0°", true, "circle", "#00ff00", 8);
var southMarker = MarkerMgr.markerHorizon("180°", "0°", true, "square", "#ffff00", 8);
var westMarker = MarkerMgr.markerHorizon("270°", "0°", true, "cross", "#ff8800", 8);

// Mark the zenith (point directly overhead)
var zenithMarker = MarkerMgr.markerHorizon("0°", "90°", true, "circled-cross", "#ffffff", 12);

// Mark a specific mountain peak at 30° altitude toward the southwest
var mountainMarker = MarkerMgr.markerHorizon("225°", "30°", true, "dotted-circle", "#88ff88", 9);

// Create a temporary marker that disappears after 10 seconds
var tempMarker = MarkerMgr.markerHorizon("180°", "45°", true, "cross", "#ffaa66", 7, false, 10000);

var markerId = MarkerMgr.markerObject("Mars", true);

if (MarkerMgr.getMarkerShow(markerId)) {
    core.debug("Marker is visible");
}

var markerId = MarkerMgr.markerObject("Jupiter", true);

// Hide the marker
MarkerMgr.setMarkerShow(markerId, false);

// Show it again later
MarkerMgr.setMarkerShow(markerId, true);

var tempMarker = MarkerMgr.markerObject("Saturn", true);

// Delete the marker when it's no longer needed
MarkerMgr.deleteMarker(tempMarker);
core.debug("Marker deleted");

// Deleting an invalid ID does nothing
MarkerMgr.deleteMarker(99999);

// Create multiple markers
var marker1 = MarkerMgr.markerObject("Mars", true);
var marker2 = MarkerMgr.markerObject("Jupiter", true);

// Clean up all markers at the end
var deletedCount = MarkerMgr.deleteAllMarkers();
core.debug("Deleted " + deletedCount + " markers");
